def _ip_to_int(ip):
    parts = ip.split(".")
    if len(parts) != 4:
        return None
    try:
        n = 0
        for p in parts:
            v = int(p)
            if v < 0 or v > 255:
                return None
            n = (n << 8) | v
        return n
    except Exception:
        return None


def _cidr_contains(ip, net_ip, prefix):
    ipn = _ip_to_int(ip)
    netn = _ip_to_int(net_ip)
    if ipn is None or netn is None:
        return False
    mask = (0xFFFFFFFF << (32 - prefix)) & 0xFFFFFFFF
    return (ipn & mask) == (netn & mask)


def _is_private_host(hostname):
    if not hostname:
        return True
    h = hostname.strip().lower()
    if h in ("localhost",):
        return True
    if re.fullmatch(r"\d{1,3}(\.\d{1,3}){3}", h):
        if ALLOW_PRIVATE_IPS:
            return False
        for net_ip, prefix in PRIVATE_NETS:
            if _cidr_contains(h, net_ip, prefix):
                return True
        return False
    return False


